import{_ as t,o as a,c as r,a2 as n}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"Teams & Roles","description":"","frontmatter":{},"headers":[],"relativePath":"app/teams.md","filePath":"app/teams.md"}'),i={name:"app/teams.md"};function o(s,e,l,m,h,d){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="teams-roles" tabindex="-1">Teams &amp; Roles <a class="header-anchor" href="#teams-roles" aria-label="Permalink to &quot;Teams &amp; Roles&quot;">​</a></h1><p>Teams group your projects, environments and members. Every project belongs to a team, and your <strong>active team</strong> determines which projects and resources you see. Each member of a team has a role that controls what they may do.</p><h2 id="create-a-team" tabindex="-1">Create a team <a class="header-anchor" href="#create-a-team" aria-label="Permalink to &quot;Create a team&quot;">​</a></h2><ol><li>Open <strong>Teams</strong> from the navigation.</li><li>Click <strong>Create Team</strong>.</li><li>Enter a name and save.</li></ol><p>The creator becomes the team <strong>Owner</strong>.</p><h2 id="switch-the-active-team" tabindex="-1">Switch the active team <a class="header-anchor" href="#switch-the-active-team" aria-label="Permalink to &quot;Switch the active team&quot;">​</a></h2><p>If you belong to more than one team, switch the active team from the team switcher in the topbar. All project, environment, domain and variable views are scoped to the active team.</p><h2 id="the-team-overview" tabindex="-1">The team overview <a class="header-anchor" href="#the-team-overview" aria-label="Permalink to &quot;The team overview&quot;">​</a></h2><p>Opening a team shows its <strong>overview</strong>: a list of projects with live deploy status, the most recent activity, and a <strong>Settings</strong> button (visible to members who may edit the team).</p><h2 id="members-and-invitations" tabindex="-1">Members and invitations <a class="header-anchor" href="#members-and-invitations" aria-label="Permalink to &quot;Members and invitations&quot;">​</a></h2><h3 id="invite-members" tabindex="-1">Invite members <a class="header-anchor" href="#invite-members" aria-label="Permalink to &quot;Invite members&quot;">​</a></h3><ol><li>Open the team and go to its <strong>Members</strong> area.</li><li>Enter one or more <strong>email addresses</strong> to invite.</li><li>Choose the <strong>role</strong> to grant (Admin or Member).</li><li>Send the invitations.</li></ol><p>Each invitee receives an email with an invitation link.</p><h3 id="accept-an-invitation" tabindex="-1">Accept an invitation <a class="header-anchor" href="#accept-an-invitation" aria-label="Permalink to &quot;Accept an invitation&quot;">​</a></h3><p>A new user opening the invitation link lands on a <strong>Complete registration</strong> page with their email pre-filled. They set their name and password to create an account and are added to the team automatically.</p><h3 id="change-a-role-or-remove-a-member" tabindex="-1">Change a role or remove a member <a class="header-anchor" href="#change-a-role-or-remove-a-member" aria-label="Permalink to &quot;Change a role or remove a member&quot;">​</a></h3><p>From the Members area you can change a member&#39;s role or remove them from the team. Both actions require the <strong>ManageMembers</strong> permission.</p><h2 id="roles-and-permissions" tabindex="-1">Roles and permissions <a class="header-anchor" href="#roles-and-permissions" aria-label="Permalink to &quot;Roles and permissions&quot;">​</a></h2><p>Tragwerk ships three roles. <strong>Owner</strong> is conferred only at team creation (or via explicit ownership transfer); when inviting or editing members you may grant <strong>Admin</strong> or <strong>Member</strong>.</p><table tabindex="0"><thead><tr><th>Permission</th><th style="text-align:center;">Owner</th><th style="text-align:center;">Admin</th><th style="text-align:center;">Member</th></tr></thead><tbody><tr><td>ViewTeam</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>EditTeam</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>ManageMembers</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td></tr><tr><td>DeleteTeam</td><td style="text-align:center;">✅</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td></tr></tbody></table><p>What each permission covers:</p><ul><li><strong>ViewTeam</strong> — see the team, its projects and environments.</li><li><strong>EditTeam</strong> — change team settings (e.g. its name).</li><li><strong>ManageMembers</strong> — invite, remove and re-role members.</li><li><strong>DeleteTeam</strong> — permanently delete the team.</li></ul><h2 id="delete-a-team" tabindex="-1">Delete a team <a class="header-anchor" href="#delete-a-team" aria-label="Permalink to &quot;Delete a team&quot;">​</a></h2><p>Deleting a team is restricted to the <strong>Owner</strong> (DeleteTeam permission). Open the team&#39;s settings and use the delete action; this removes the team and confirm the action in the dialog.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting a team removes its association with its projects and resources. Make sure nothing important depends on it first.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/projects">Projects</a></li><li><a href="/app/account">Account</a></li><li><a href="/app/environments">Environments</a></li></ul>',27)])])}const g=t(i,[["render",o]]);export{p as __pageData,g as default};
